   29: void f2fs_stop_checkpoint(struct f2fs_sb_info *sbi, bool end_io,
   30: 						unsigned char reason)
   31: {
   32: 	f2fs_build_fault_attr(sbi, 0, 0);
   33: 	if (!end_io)
   34: 		f2fs_flush_merged_writes(sbi);
   35: 	f2fs_handle_critical_error(sbi, reason, end_io);
