  906: 	if (cur_version == pre_version) {
  907: 		*version = cur_version;
  908: 		f2fs_put_page(cp_page_2, 1);
  909: 		return cp_page_1;
  910: 	}
  911: 	f2fs_put_page(cp_page_2, 1);
  912: invalid_cp:
  913: 	f2fs_put_page(cp_page_1, 1);
  914: 	return NULL;
  915: }
