  689: 	err = fscrypt_prepare_symlink(dir, symname, len, dir->i_sb->s_blocksize,
  690: 				      &disk_link);
  691: 	if (err)
  692: 		return err;
  693: 
  694: 	err = f2fs_dquot_initialize(dir);
  695: 	if (err)
  696: 		return err;
