 4571: 			sit_blk = (struct f2fs_sit_block *)page_address(page);
 4572: 			sit = sit_blk->entries[SIT_ENTRY_OFFSET(sit_i, start)];
 4573: 			f2fs_put_page(page, 1);
 4574: 
 4575: 			err = check_block_count(sbi, start, &sit);
 4576: 			if (err)
 4577: 				return err;
