 4591: 				/* build discard map only one time */
 4592: 				if (is_set_ckpt_flags(sbi, CP_TRIMMED_FLAG)) {
 4593: 					memset(se->discard_map, 0xff,
 4594: 						SIT_VBLOCK_MAP_SIZE);
